boldRegex) }            italicMatch?.let { candidates.add(it.range.first to italicRegex) }            linkMatch?.let { candidates.add(it.range.first to linkRegex) }            if (candidates.isEmpty()) {                appendAnimeTitles(remaining, animeTitles, primary)                break            }            candidates.sortBy { it.first }            val (_, chosenRegex) = if (candidates.size > 1 && candidates[0].first == candidates[1].first) {                val bold = candidates.find { it.second == boldRegex }                if (bold != null) bold else candidates.first()            } else {                candidates.first()            }            val match = chosenRegex.find(remaining)!!            if (match.range.first > 0) {                appendAnimeTitles(remaining.substring(0, match.range.first), animeTitles, primary)            }            when (chosenRegex) {                boldRegex -> {                    pushStyle(SpanStyle(fontWeight = FontWeight.Bold))                    appendWithAnimeLinks(match.groupValues[1], animeTitles, primary)                    pop()                }                italicRegex -> {                    pushStyle(SpanStyle(fontStyle = FontStyle.Italic))                    appendWithAnimeLinks(match.groupValues[1], animeTitles, primary)                    pop()                }                linkRegex -> {                    val url = match.groupValues[2]                    pushStringAnnotation("URL", url)                    pushStyle(SpanStyle(                        color = primary,                        textDecoration = TextDecoration.Underline                    ))                    append(match.groupValues[1])                    pop()                    pop()                }            }            remaining = remaining.substring(match.range.last + 1)        }        addStyle(SpanStyle(color = color), 0, length)    }}private fun AnnotatedString.Builder.appendWithAnimeLinks(text: String, animeTitles: Map<String, Int>